import './Rotation.scss';

import { IconButton } from ':components/IconButton';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import React from 'react';

export interface RotationProps {
	onRotateLeft: (event) => void;
	onRotateRight: (event) => void;
}

export const Rotation = ({ onRotateLeft, onRotateRight }: RotationProps) => (
	<div className="dsb_preview__rotation">
		<IconButton iconName={Icons.Clockwise} variant="base" onClick={onRotateRight} />
		<IconButton iconName={Icons.Counterclockwise} variant="base" onClick={onRotateLeft} />
	</div>
);
